--
-- Estrutura para view `vw_dashboard_financeiro_obra`
--
DROP TABLE IF EXISTS `vw_dashboard_financeiro_obra`;

CREATE ALGORITHM=UNDEFINED DEFINER=`u268549871_saas`@`127.0.0.1` SQL SECURITY DEFINER VIEW `vw_dashboard_financeiro_obra`  AS SELECT `o`.`id` AS `obra_id`, `o`.`numero` AS `obra_numero`, `o`.`nome` AS `obra_nome`, `c`.`nome` AS `cliente_nome`, `fp`.`mes_referencia` AS `mes_referencia`, coalesce(`f`.`valor_total_fatura`,0) AS `receita_total`, coalesce(`f`.`valor_total_servicos`,0) AS `receita_servicos`, coalesce(`f`.`igi_valor`,0) AS `receita_igi`, coalesce(sum(`fp`.`custo_total_empresa`),0) AS `custo_total`, coalesce(sum(`fp`.`liquido_a_pagar`),0) AS `custo_liquido_funcionarios`, coalesce(sum(`fp`.`cas_custo_empresa_valor`),0) AS `custo_cas_empresa`, coalesce(`f`.`valor_total_fatura`,0) - coalesce(sum(`fp`.`custo_total_empresa`),0) AS `lucro`, CASE WHEN coalesce(`f`.`valor_total_fatura`,0) > 0 THEN (coalesce(`f`.`valor_total_fatura`,0) - coalesce(sum(`fp`.`custo_total_empresa`),0)) / coalesce(`f`.`valor_total_fatura`,0) * 100 ELSE 0 END AS `margem_percentual` FROM (((`obras` `o` left join `clientes` `c` on(`c`.`id` = `o`.`cliente_id`)) left join `folha_pagamento` `fp` on(`fp`.`obra_id` = `o`.`id`)) left join `faturamento` `f` on(`f`.`obra_id` = `o`.`id` and `f`.`mes_referencia` = `fp`.`mes_referencia`)) WHERE `o`.`ativa` = 1 GROUP BY `o`.`id`, `c`.`nome`, `fp`.`mes_referencia`, `f`.`valor_total_fatura`, `f`.`valor_total_servicos`, `f`.`igi_valor` ;

